const body = $input.first().json.body;
const briefId = body.briefId;
const assembledBrief = body.assembledBrief || '';
const ideaPrompt = body.ideaPrompt || '';
const webSources = body.webSources || [];

// Build extraction prompt with full context
let context = `Idea: ${ideaPrompt}\n\nResearch Brief (excerpt):\n${assembledBrief.slice(0, 30000)}`;

if (webSources.length > 0) {
  context += '\n\n## Web Sources:\n';
  for (const s of webSources.slice(0, 20)) {
    context += `- [${s.sourceType || s.source_type}] ${s.title} (trust: ${s.trustScore || s.trust_score}) ${s.url}\n`;
  }
}

return [{ json: { briefId, context, ideaPrompt } }];

const items = $input.all();
let tasks = [];
for (const item of items) {
  const content = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  try {
    const jsonMatch = content.match(/\[[\s\S]*\]/);
    if (jsonMatch) {
      let raw = jsonMatch[0];
      // Sanitize JSON
      raw = raw.replace(/"((?:[^"\\]|\\.)*)">/g, (_m, inner) =>
        '"' + inner.replace(/\n/g, '\\n').replace(/\r/g, '').replace(/\t/g, '\\t') + '"'
      );
      raw = raw.replace(/,\s*([\]\}])/g, '$1');
      tasks = JSON.parse(raw);
    }
  } catch (e) {
    // Try object-by-object extraction
    const matches = content.match(/\{[^{}]*"title"\s*:\s*"[^"]+[^{}]*\}/g) || [];
    for (const m of matches) {
      try {
        const sanitized = m.replace(/"((?:[^"\\]|\\.)*)">/g, (_m, inner) =>
          '"' + inner.replace(/\n/g, '\\n').replace(/\r/g, '') + '"'
        );
        const obj = JSON.parse(sanitized);
        if (obj.title) tasks.push(obj);
      } catch {}
    }
  }
}

tasks = tasks.filter(t => t && t.title && t.title.length > 3);

return [{ json: { tasks, count: tasks.length, briefId: $('Webhook Trigger').item.json.body.briefId } }];
